+    OUTPUT=$("$RCH" fleet deploy --resume --dry-run 2>&1) || true
+    log "  Resume output:"
+    echo "$OUTPUT" | head -20 | while read -r line; do log "    $line"; done
+
+    # Should indicate no previous state or resume behavior
